class AllOne {
public:
    unordered_map<string, int> count;
    multiset<int> maxSet;
    multiset<int> minSet;

    AllOne() {

    }

    void inc(string key) {
        if (count.find(key) == count.end()) {
            count[key] = 1;
        } else {
            count[key]++;
        }
        maxSet.insert(count[key]);
        minSet.insert(count[key]);
    }

    void dec(string key) {
        count[key]--;
        maxSet.erase(maxSet.find(count[key]));
        minSet.erase(minSet.find(count[key]));
        if (count[key] == 0) {
            count.erase(key);
        }
    }

    string getMaxKey() {
        if (maxSet.empty()) {
            return "";
        }
        return *maxSet.rbegin();
    }

    string getMinKey() {
        if (minSet.empty()) {
            return "";
        }
        return *minSet.begin();
    }
};
```
